#include <stdio.h>

void min_max(int a, int b, int *min, int *max) {
    if (a < b) {
        *min = a; *max = b;
    } else {
        *min = b; *max = a;
    }
}

int main() {
    int a = 2, b = 3;
    int min_br, max_br;

    min_max(a, b, &min_br, &max_br);

    printf("Min: %d\n", min_br);
    printf("Max: %d\n", max_br);

    return 0;
}
